// app/api/auth/[...nextauth]/route.ts
import NextAuth from 'next-auth';
import Providers from 'next-auth/providers'; // Use the general Providers import
import type { NextAuthOptions } from 'next-auth';

// Define a configuration function to encapsulate provider settings
function getProviderConfig() {
  return [
    Providers.GitHub({
      clientId: process.env.GITHUB_CLIENT_ID!,
      clientSecret: process.env.GITHUB_CLIENT_SECRET!,
    }),
  ];
}

// Define session and JWT handling directly in the options
export const authOptions: NextAuthOptions = {
  providers: getProviderConfig(), // Use the encapsulated function for providers
  session: {
    strategy: 'jwt',
  },
  callbacks: {
    session({ session, token }) {
      session.user = session.user ? { ...session.user, id: token.sub } : undefined;
      return session;
    },
    jwt({ token, user }) {
      return user ? { ...token, id: user.id } : token;
    },
  },
  secret: process.env.NEXTAUTH_SECRET,
};

const authHandler = NextAuth(authOptions); // Simplify handler naming for clarity
export { authHandler as GET, authHandler as POST }; // Export using simplified names
